var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"동력부 85% 손상! 더 이상 충격을 받게 될 경우 배터리 유폭의 위험이 있음!","JPN":"動力部85％損傷。これ以上衝撃を受けるとバッテリー誘爆の危険あり。","ENG":"85% damage to the engine! Any more impact will cause the batteries to explode!","TWN":"動力部受損85%！若繼續受到衝擊，將會發生電池爆炸的危險！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L4_1","type":"dialog","speaker":"GAP_BLACK_NULL_NULL","text":{"KOREA":"후훗, 날 이렇게까지 몰아붙이다니. 굉장한 호적수로군!","JPN":"ふふっ、私をここまで追い詰めるとは。なかなかの敵だな！","ENG":"Hah hah. You're pretty good, pressing me so hard like this!","TWN":"呵呵，竟然能把我逼到這種地步，真是個強勁的好對手！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_BLACK_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"아앗, 이 오토튠이 잔뜩 들어간 목소린......설마?","JPN":"あっ、このオートチューンを使ったような声……まさか？","ENG":"Ah, this electronically distorted voice! Can it be him?","TWN":"啊啊，這個透過變聲器的聲音……難道是？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님! 선배님이 안에 타고 계신 거 맞죠?!","JPN":"先輩！　先輩がここに乗っているんですか！？","ENG":"Dark! Is that you in there?","TWN":"前輩！是你坐在機器人裡面嗎？！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하하...... 후배님을 이렇게 다시 만나다니.","JPN":"はは……後輩にこんなところで会えるとは。","ENG":"Hah hah. We met again, Lone.","TWN":"哈哈……竟然會這樣再見到後輩。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"이거 참 부끄러운 걸.","JPN":"少し恥ずかしいな。","ENG":"This is embarrassing.","TWN":"真是丟臉啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"아직은 이런 식으로 다시 만나고 싶지 않았는데 말이야.","JPN":"まだこんな風に会いたくはなかったのだが。","ENG":"I didn't want to see you like this... yet.","TWN":"我還真不想用這種方式和妳重逢呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"어째서 여기 계신 거죠?!","JPN":"どうしてここにいるんですか！？","ENG":"What are you doing here?","TWN":"你為什麼會在這裡？！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"세계를 정복하러 가신 게 아니었나요?","JPN":"世界を征服しに行ったのでは？","ENG":"I thought you'd be busy dominating the world.","TWN":"你不是踏上征服世界的道路了嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하하, 물론이지. 하지만 더 이상 폭력이 아닌 흥겨운 비트로 세계를 정복하는 것이 나의 원대한 꿈이라네.","JPN":"はは、もちろんだ。しかし、暴力ではなく、楽しいビートで世界を征服するのが私の夢なのだ。","ENG":"Hah hah, yes, I am. It's just that I'm not trying to dominate it with force; I'm trying to dominate it with rhythm.","TWN":"哈哈，當然啊。但不是用暴力，我的偉大夢想是用歡樂的節奏去征服世界。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"미워하고 부수는 것만이...... 세계정복을 이룰 수 있는 유일한 길은 아니니까.","JPN":"憎しみ壊すことだけが……世界征服を成せる唯一の道ではないからな。","ENG":"Hatred and destruction aren't the only solutions to world domination.","TWN":"仇恨和破壞……並不是征服世界的唯一一條路。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하지만 후배님이 위험에 처하는 걸 그냥 두고 볼 수는 없었지.","JPN":"しかし、後輩が危機的状況にあるのを見過ごすことはできなかった。","ENG":"But then I saw you in danger. I couldn't just stand aside.","TWN":"只是看到後輩身陷於危險中，我不能置之不理。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"다행히 너무 늦지는 않은 것 같군.","JPN":"幸い手遅れにならずに済んだようだ。","ENG":"I'm glad I'm not late.","TWN":"幸好我來得不算太晚。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"죄송해요, 선배님. 제가...... 제가 바보같이 구는 바람에!","JPN":"ごめんなさい、先輩。私……私がバカだから！","ENG":"I'm sorry, Dark. I... I've caused all this, like the fool I am!","TWN":"對不起，前輩。都怪我……都怪我太愚蠢！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그렇게...... 슬픈 표정 짓지 말게.","JPN":"そんな……悲しい顔をしないでくれ。","ENG":"Please don't fret.","TWN":"不要……露出那麼悲傷的表情。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"난 후배님이 더 이상 꿈을 위해 누군가를, 그리고 자신을 해치지 않길 바랄 뿐이야.","JPN":"私は後輩がこれ以上夢のために誰かを、そして自分を傷つけることがないよう願うだけだ。","ENG":"I just don't want you to hurt others or yourself for the sake of your dreams.","TWN":"我只希望後輩不要再為了自己的夢想傷害別人，也傷害自己了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님께선 이런 저를 또 다시 이렇게 구원해주시는군요.","JPN":"先輩はこんな私をまた救ってくださるのですね。","ENG":"Dark, you're saving me yet again.","TWN":"這次前輩又救了我一次。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"죄송해요. 다신 제 사사로운 욕심 때문에 누군가를 해치려 들지 않을게요.","JPN":"本当にごめんなさい。もう二度と自分の欲を満たすために、誰かを傷つけたりしません。","ENG":"I'm sorry. I promise I'll never hurt anyone for my selfish desires.","TWN":"對不起，我不會再為了自己的私欲傷害別人的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하하, 그럼 된 걸세.","JPN":"はは、それならいい。","ENG":"Hah hah. That's all I want to hear.","TWN":"哈哈，那就好。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"난 이제 가봐야겠군.","JPN":"私はそろそろ行くとしよう。","ENG":"Now, I'd better go.","TWN":"那麼我該走了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"가신다니요? 그게 무슨 말씀이세요?","JPN":"え？　行くって、どういうことですか？","ENG":"Go? Where?","TWN":"走？你要做什麼？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"저기에 보란 듯이 내 적수가 기다리고 있지 않나?","JPN":"あそこに私の敵が待っているからな。","ENG":"To my adversary right there.","TWN":"我的對手不是還在那裡等著我嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"싸움에 마무리를 지어야지.","JPN":"戦いを終わらせなければならない。","ENG":"I have to finish the fight.","TWN":"我必須要結束戰鬥才行。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"자, 가자! 머신-갓 다크! 최후의 승부를 가릴 때가 왔다!","JPN":"さぁ、行くぞ！　マシーンG.O.Dタイプ：ダーク！　最後の戦いに決着をつけるぞ！","ENG":"Alright, let's go. Machine G.O.D. Dark! It's time for a showdown!","TWN":"好，上吧！MACHINE-GOD TYPE：DARK！最後的決鬥要開始了！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_27"},{"id":"L37_1","type":"dialog","speaker":"GAP_BLACK_NULL_NULL","text":{"KOREA":"명령 확인! 출력 과부하! 최고 전력 전개!","JPN":"命令確認！　過負荷出力！　最高戦力展開！","ENG":"Command confirmed. Maximizing output... Operating at the maximum capacity!","TWN":"收到命令！功率超載！最高戰力全開！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_BLACK_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_22"},{"id":"L39_1","type":"dialog","speaker":"GAP_GOLD_NULL_NULL","text":{"KOREA":"휘두른다! 쏜다! 부순다! 파괴한다!","JPN":"振り回す！　撃つ！　潰す！　破壊する！","ENG":"Swing! Fire! Break! Destroy!","TWN":"揮舞！發射！命中！破壞！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GAP_GOLD_NULL_NULL","text":{"KOREA":"최종 섬멸 프로세스 기동!","JPN":"最終殲滅プロセス起動！","ENG":"Activating the annihilation process!","TWN":"終極殲滅程式啟動！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAP_GOLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_22"},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"우오오오오옷!!","JPN":"うおおおおお！！","ENG":"Kkkohhhhh!","TWN":"唔喔喔喔喔！！"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_ENERGY_CHARGE"},{"id":"L49_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배님! 안돼요!","JPN":"先輩！　やめてください！","ENG":"Dark! Nooooo!","TWN":"前輩！不要！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LONELY_NPC_SUMMER_NULL","text":{"KOREA":"선배니임---------!!!!!!!","JPN":"せんぱーーーい！！！！","ENG":"Daaaaaaark!","TWN":"前輩——！！！！！！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"BATTLE_VIRTUAL_2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"시, 신호 소실!","JPN":"し、信号消失！","ENG":"W-we lost its signals!","TWN":"信、信號消失！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"양측의 로봇이 같이 파괴된 것 같습니다, 어떡할까요!","JPN":"双方のロボットが同時に破壊されたようです、どうしますか？","ENG":"Both robots must have been destroyed. What do we do?","TWN":"兩個機器人好像同歸於盡了，怎麼辦！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"이런 바보 같은 일이......","JPN":"そんなバカなことが……","ENG":"No way!","TWN":"怎麼會這樣……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"하지만 최종전 보스는 3페이즈까지 있","JPN":"しかし、最終戦のボスは3フェイズまで……","ENG":"The last boss has three phases—","TWN":"但最終BOSS有第三階"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_FOX_ENEMY_BOSS","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_BOSS","text":{"KOREA":"......크억!!","JPN":"ガハッ……！","ENG":"Kkkhhhkkk!","TWN":"……唔呃！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_07"},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_SUMMER_NULL","text":{"KOREA":"다음 페이즈 같은 건 없어. 너흰 여기서 끝이다, 이 3류 악당 범죄자!","JPN":"次のフェイズなんてない。あなたたちはここで終わりよ、この三流悪党め！","ENG":"There will be no more phases. This is as far as you go, you third-rate criminals!","TWN":"沒有下一階段了，到此為止了，你們這些三流反派罪犯！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIFLE_FOX_ENEMY_NULL","text":{"KOREA":"항복! 항복합니다!","JPN":"降伏！　降伏します！","ENG":"Surrender! We surrender!","TWN":"投降！我們投降！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_ENEMY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"경찰 아가씨! 손님들 다 대피시키고 왔어......","JPN":"警察さーん！　お客さんたちは全員避難させて……","ENG":"Lady cop, I've evacuated all the guests—","TWN":"警察小姐！客人已經疏散完畢了……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LIV_ZODIAC_SUMMER_NULL","text":{"KOREA":"어라? 벌써 다 끝난 거야?","JPN":"あれ？　もう終わったの？","ENG":"Err, is it over already?","TWN":"咦？這麼快？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"하아...... 힘들었다.","JPN":"はぁ……疲れた。","ENG":"*Sigh* That was tough.","TWN":"哈啊……累死了。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"모처럼 휴양지에서 쉴 수 있을 줄 알았는데 이게 무슨 꼴이람.","JPN":"せっかくリゾート地で休めると思ったのに、なんでこんなことに。","ENG":"I thought I could rest at this resort... Not.","TWN":"還以為能在度假勝地好好休息，結果這算什麼啊。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"그래도 불꽃놀이 정도는 마음 편하게 구경할 수 있을 것 같네. 멋지다.","JPN":"でも花火大会はゆっくり見られそうでよかった。綺麗……","ENG":"But at least now I can watch the fireworks without interruption. It looks so beautiful.","TWN":"不過至少能好好欣賞煙火表演了，真是漂亮。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_FIREWORK"},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_SUMMER_NULL","text":{"KOREA":"그렇군요. 꽤나 적절한 타이밍에 큰 한 방이 터졌어요.","JPN":"そうですね。いいタイミングで大きな花火が打ち上げられましたわ。","ENG":"It is. That big one burst at the right time.","TWN":"是啊，這煙火放得真是時候。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_SUMMER_NULL","text":{"KOREA":"음...... 그런데, 저 불꽃은 왜 산타클로스처럼 보이는 거지?","JPN":"う～ん……でも、あの花火。サンタクロースみたいに見えるのは気のせい？","ENG":"Mm... By the way, is it just me or does that really look like Santa Claus?","TWN":"呃……不過，那個煙火為什麼看起來像聖誕老人？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_SUMMER_NULL","text":{"KOREA":"아무래도 유람선에 있는 이디스의 페스티벌 로봇이 작년 크리스마스 축제 이후로 날짜를 수정하지 못한 것 같군요.","JPN":"おそらく遊覧船にいるイーディスのフェスティバルロボットが、昨年のクリスマスから日付を変えていないようですね。","ENG":"It seems Edith's festival robot on the cruise ship must have not been updated since the Christmas festival.","TWN":"大概是遊輪上配置的伊蒂絲慶典機器人在去年的耶誕節之後，還沒有更新日期吧。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHAIR_SCHOOL_SUMMER_NULL","text":{"KOREA":"음냐...... 헤헤......","JPN":"へへ……","ENG":"Zzz... Heh...","TWN":"唔喵……嘿嘿……"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"다치신 곳은 없나요?","JPN":"お怪我はありませんか？","ENG":"Are you hurt anywhere?","TWN":"您沒受傷吧？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"응, 난 괜찮아.","JPN":"うん、大丈夫よ。","ENG":"No. I'm fine.","TWN":"嗯，我沒事。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"참 정신 없는 하루였다, 그렇지?","JPN":"騒がしい一日だったわね？","ENG":"What an eventful day, huh?","TWN":"真是忙碌的一天呢，對吧？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"그러네요. 좀 더 조용하게 휴식을 만끽할 수 있었으면 좋았을 텐데요.","JPN":"そうですね。もう少し静かに休暇を楽しめたら良かったのですが。","ENG":"It was. I'm sorry you couldn't enjoy your downtime like you wanted to.","TWN":"就是啊，如果能安靜地享受假期就好了。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"아냐! 난 이런 것도 제법 재미있었는걸?","JPN":"ううん、これはこれでなかなか楽しかったわ！","ENG":"It's okay. I had a blast all day.","TWN":"不！我覺得這樣也很有趣呢？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"어렸을 때는 이렇게 앉아서 같이 불꽃놀이 구경도 많이 했던 것 같은데.","JPN":"昔はよく、こんな風に一緒に座って花火を見てたわね。","ENG":"I think we used to watch fireworks often, sitting together like this, when we were young.","TWN":"小時候我們也經常像這樣，一起坐著看煙火表演。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"......그렇습니다.","JPN":"……なるほど。","ENG":"Yes.","TWN":"……是的。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"늘 가까이에 있었지만, 정작 마음은 너무 오랫동안 떨어져 있었던 것 같아.","JPN":"いつも傍にいるけど、心は長い事離れ離れになっていたような気がする。","ENG":"Even though we've been together, we weren't really close to each other.","TWN":"雖然我們總是形影不離，但最重要的心卻有很長一段時間都離得很遠。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"그러니까, 앞으론 우리 가끔은......","JPN":"だから、これからはたまには……","ENG":"So, I think we should...","TWN":"所以，以後我們偶爾……"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_SUMMER_NULL","text":{"KOREA":"자매답게, 같이 놀러 다니자, 치후유.","JPN":"姉妹らしく、一緒に遊ぼうね？　千冬。","ENG":"We should go have some fun together sometimes, like the good sisters that we are, Chifuyu.","TWN":"也像一對姐妹一樣，一起出來玩吧，千冬。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_SUMMER_NULL","text":{"KOREA":"응...... 치나츠 언니.","JPN":"うん……姉さん。","ENG":"Okay, Chinatsu.","TWN":"嗯……千夏姐姐。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"운명의 실 같은 건 더 이상 보이지 않는군. 마법의 유효기간이 다 끝난 모양이지?","JPN":"運命の糸みたいなものがもう見当たらない。魔法の有効期限が過ぎてしまったようだな？","ENG":"I don't see the threads of destiny anymore. The magic must have worn off.","TWN":"看不到命運之線了呢，看來魔法的時效過了吧？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"......저주가 아닌 다른 것들을 보는 기분도 썩 나쁘진 않았어.","JPN":"……呪いではない他のものを見るのも、なかなか気持ちがいいものだ。","ENG":"It wasn't too bad, seeing something other than curses.","TWN":"……不看詛咒，能看到其他東西的感覺也很不錯呢。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEEJISOO_SIX_SUMMER_NULL","text":{"KOREA":"마법이 조금만 더 오래갔다면 대장의 운명도 한 번 봐주면 좋았을 텐데 아쉽군.","JPN":"魔法が切れる前に、隊長の運命も見ておきたかったが残念だな。","ENG":"I wish the magic lasted longer. I could have seen the Captain's destiny.","TWN":"如果魔法再持續得長一點，說不定還能看到隊長的命運，真是可惜。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"와아...... 멋져라. 정말 예쁜 불꽃들이네요.","JPN":"わぁ……素敵。本当に綺麗なお花ですね。","ENG":"Wow, gorgeous! Those sparks look so pretty.","TWN":"哇……好漂亮，煙火真的好漂亮。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"지식을 섭취할 때와 비슷한 고양감이지만, 뭔가 색다른 기분이 들어요.","JPN":"知識を摂取する時と似たような高揚感ですが、何か真新しい気分です。","ENG":"It's so exciting, like when we're ingesting knowledge, but in a different way.","TWN":"我們感受到了和攝取知識時同樣的興奮感，但又好像有點不一樣。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"레지나 님도 같이 보셨다면 더 좋았을 텐데.","JPN":"レジーナさんも一緒に見ることができたらよかったのに。","ENG":"It would have been better if Miss Regina were here to watch this with us.","TWN":"如果蕾佳娜大人也在就好了。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"아......!","JPN":"あっ……！","ENG":"Ah!","TWN":"啊……！"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"학회에 돌아갈 때 폭죽을 잔뜩 싸 들고 가야겠어요.","JPN":"学会に戻るとき、花火の火薬をたくさん持って行きましょう。","ENG":"Let's grab a load of fireworks on our way back to the Society.","TWN":"回學會的時候，我們要帶很多煙火回去。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_SUMMER","text":{"KOREA":"분명 좋아하시겠죠?","JPN":"絶対に喜ぶはずです。","ENG":"She'd love them, wouldn't she?","TWN":"她一定會很高興吧？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_SUMMER","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(......많은 걸 배운 것 같군 형제.)","JPN":"(……たくさんのことを学んだようだ。)","ENG":"(I think we've learned a lot, brother.)","TWN":"（……我們好像學到了很多東西啊，兄弟。）"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_09"},{"id":"L8_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(진정한 사랑과 헌신, 인생의 의미까지도 깨달은 기분이야 형제.)","JPN":"(真の愛と献身、人生の意味まで悟れた気分だ。)","ENG":"(I feel as if I've learned the meanings of true love, devotion, and even life, brother.)","TWN":"（我感受到了真愛和獻身，以及人生意義的實現，兄弟。）"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_08"},{"id":"L9_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(그래. 그리고 그저 매달리기만 하는 건 진정한 사랑이 아니라는 것도.)","JPN":"(そうだな。そしてただすがるだけが真の愛ではないということも。)","ENG":"(Yes. And that it's not love, holding onto someone who doesn't want you.)","TWN":"（沒錯，還有真愛並不是一味地糾纏。）"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_17"},{"id":"L10_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(남은 건 그녀가 행복하기를 기원하는 내 마음뿐이지.)","JPN":"(残るのは彼女が幸せになることを願う俺の気持ちだけだ。)","ENG":"(All I want now is her happiness.)","TWN":"（現在我只希望她能夠幸福。）"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_16"},{"id":"L11_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(어이, 저길 봐. 굉장한 불꽃이야.)","JPN":"(おい、あれを見ろ。すごい花火だ。)","ENG":"(Look at that! What a beautiful firework.)","TWN":"（喂，你們看，好壯觀的煙火。）"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_02"},{"id":"L12_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(아아...... 굉장한 색이로군.)","JPN":"(あぁ……すごい色だな。)","ENG":"(Oh... What amazing colors.)","TWN":"（啊啊……好漂亮。）"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_03"},{"id":"L13_1","type":"dialog","speaker":"OGRE1_NPC_NULL_NULL","text":{"KOREA":"(아아...... 정말이야)","JPN":"(あぁ……本当だ。)","ENG":"(You're right.)","TWN":"（嗯……我真的）"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_15"},{"id":"L14_1","type":"dialog","speaker":"OGRE2_NPC_NULL_NULL","text":{"KOREA":"(마치......)","JPN":"(まるで……)","ENG":"(Everything should end like that.)","TWN":"（好像……）"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_14"},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"와아~ 살면서 본 것 중에 제일 화려한 불꽃놀이 같아요. 그렇지 않나요 카린 양?","JPN":"わぁ～、今までで一番綺麗な花火です。カリンさんも、そう思いませんか？","ENG":"Wow! This is by far the most gorgeous fireworks display I've ever seen. What about you, Karin?","TWN":"哇～這是我見過最華麗的煙火了，對吧，卡琳小姐？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"이런 축제는 꽤 오래 전에 사라진 걸로 알고 있는데, 시영 씨는 어릴 때 불꽃놀이를 본 적이 있었나 보죠?","JPN":"このようなお祭りは遠い昔になくなったとばかり思っていましたが、\\nシノンさんは子供の頃に花火大会に行ったことがあるのですか？","ENG":"Festivals like this haven't been held for a long time in our world. You must have seen fireworks when you were young.","TWN":"據我所知，我們這種慶典已經消失很久了，時雨小姐的煙火是在小時候看的嗎？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"하하, 저렇게 하늘 높이 올라가는 큰 불꽃은 아니었지만요.","JPN":"ハハッ、あんな空高く打ち上げられる花火ではありませんが。","ENG":"Hah hah. Yes, but they weren't so big or high in the sky like these.","TWN":"哈哈，我那時看的煙火飛得沒這麼高，也沒那麼大。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"......어라?","JPN":"……あれ？","ENG":"Err?","TWN":"……咦？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"왜 그러시죠?","JPN":"どうしたんですか？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"몸이...... 점점 투명해지는 것 같아요. 저희 곧 원래 세계로 돌아가려나 본데요?","JPN":"体が……どんどん透明になってる気がします。私たち、元の世界に戻る時間みたいです。","ENG":"Your body... It's becoming transparent. I think we're about to go back to our world.","TWN":"身體……越變越透明了，這是我們馬上就要回到原本世界的意思吧？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"투명해지면서 사라지는 몸이라니, 정말이지 클리셰로 얼룩진 엔딩이네요.","JPN":"透明になって消える体とは、どこかで見たことのあるようなエンディングですね。","ENG":"Becoming transparent and disappearing in the end? This story is filled with cliches until the end, isn't it?","TWN":"身體變透明後消失，還真是老套的結局啊。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"후훗, 역시 카린 양도 막상 돌아가려니 아쉬운가 보죠?","JPN":"ふふっ、さすがにカリンさんもいざ帰るとなると心惜しいみたいですね？","ENG":"Hah hah. You're disappointed to go back, aren't you?","TWN":"呵呵，卡琳小姐是不是也捨不得回去？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"우리가 있어야 할 곳으로 돌아가는 것뿐입니다. 잘 알잖아요?","JPN":"私たちがいるべき場所に戻るだけです。よくわかってるではありませんか？","ENG":"We're going back to where we belong. You know that.","TWN":"我們只是回到該回的地方而已，妳不是很清楚嗎？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"너무 아쉬워하지 마세요. 운명에 이끌려 여기 온 것처럼, 언젠가 또 오게 될지도 모르는 거잖아요?","JPN":"心惜しくもありますが、運命に導かれてここに来たように、いつかまた来れるかもしれませんからね？","ENG":"Don't be so disappointed. Our destiny might bring us here again one day.","TWN":"不用覺得可惜啦。我們這次是被命運帶領過來的，也許哪天我們還會再到這裡啊？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"......그때도 혼자 먼저 가버리면 정말 화낼 줄 알아요.","JPN":"……その時も、また一人で先に行ったら許しませんよ。","ENG":"You'd better not leave me behind again.","TWN":"……如果妳那時候又一個人先去，我一定會生氣的。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"아 참!","JPN":"あっ、そうだ！","ENG":"Oh, right!","TWN":"對了！"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_APSUMMER_NULL","text":{"KOREA":"또 뭐에요?","JPN":"また何ですか？","ENG":"What now?","TWN":"又怎麼了？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"깜박 하고 있던 게 떠올라서요.","JPN":"うっかり忘れてましたが、","ENG":"I almost forgot.","TWN":"我想起了一件事。"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_APSUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_APSUMMER_NULL","text":{"KOREA":"우리 의뢰인 님은 그래서 결국 어떻게 됐으려나......?","JPN":"私たちの依頼人は結局、どうなったのでしょうか？","ENG":"What happened to our client lady?","TWN":"我們的客戶大人最後不知道怎麼樣了呢……？"},"stage":{"bg":"SUMMER_07","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_APSUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_FIREWORK"}]`);export{e as default};